const checkpoints = [];

function parseIso(d) {
  const dt = new Date(d);
  return isNaN(dt.getTime()) ? null : dt;
}

function minutesOfDay(date) {
  return date.getUTCHours() * 60 + date.getUTCMinutes();
}

const services = JSON.parse(localStorage.getItem('worship_services') || '[]');
const programs = JSON.parse(localStorage.getItem('childrens_programs') || '[]');
const visitPlans = JSON.parse(localStorage.getItem('visit_plans') || '[]');

const plan = visitPlans.find(p => p && (p.status === 'planning' || p.status === 'confirmed')) || null;

// Build list of qualifying services based on task criteria
const qualifyingServices = services.filter(s => {
  if (!s || !s.isActive) return false;
  if (s.dayOfWeek !== 'sunday') return false;
  if (!s.hasChildrenProgram) return false;
  const start = parseIso(s.startDateTime);
  if (!start) return false;
  const mins = minutesOfDay(start);
  if (mins < 9 * 60 || mins > 11 * 60) return false; // 9:00–11:00
  const cps = programs.filter(cp => cp.serviceId === s.id && cp.isActive);
  const hasAgeProgram = cps.some(cp => typeof cp.ageMin === 'number' && typeof cp.ageMax === 'number' && cp.ageMin <= 5 && cp.ageMax >= 10);
  return hasAgeProgram;
});

let earliestService = null;
if (qualifyingServices.length > 0) {
  earliestService = qualifyingServices.slice().sort((a, b) => {
    const da = parseIso(a.startDateTime) || 0;
    const db = parseIso(b.startDateTime) || 0;
    return da - db;
  })[0];
}

const planService = plan ? services.find(s => s.id === plan.serviceId) : null;
const planServiceQualifies = !!(planService && qualifyingServices.some(s => s.id === planService.id));
const choseEarliestService = !!(earliestService && planService && planService.id === earliestService.id);

// Children’s program in plan that matches criteria and belongs to the selected service
const planChildrenIds = (plan && Array.isArray(plan.childrenProgramIds)) ? plan.childrenProgramIds : [];
const planPrograms = programs.filter(cp => planChildrenIds.indexOf(cp.id) !== -1 && cp.serviceId === (plan ? plan.serviceId : null) && cp.isActive);
const qualifyingPlanPrograms = planPrograms.filter(cp => typeof cp.ageMin === 'number' && typeof cp.ageMax === 'number' && cp.ageMin <= 5 && cp.ageMax >= 10);
const hasQualifyingProgramInPlan = qualifyingPlanPrograms.length > 0;

// CP1 (0.40): Visit plan uses a service that satisfies all service criteria
checkpoints.push({ passed: planServiceQualifies, weight: 0.4 });

// CP2 (0.30): Chosen service is the earliest among all qualifying services
checkpoints.push({ passed: planServiceQualifies && choseEarliestService, weight: 0.3 });

// CP3 (0.30): Visit plan includes at least one children’s program for ages 5–10 attached to that service
checkpoints.push({ passed: planServiceQualifies && hasQualifyingProgramInPlan, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

function parseIso(d) {
  const dt = new Date(d);
  return isNaN(dt.getTime()) ? null : dt;
}

function minutesOfDay(date) {
  return date.getUTCHours() * 60 + date.getUTCMinutes();
}

const events = JSON.parse(localStorage.getItem('events') || '[]');
const regs = JSON.parse(localStorage.getItem('event_registrations') || '[]');

const today = new Date();
const monthStart = new Date(Date.UTC(today.getUTCFullYear(), today.getUTCMonth(), 1));
const monthEnd = new Date(Date.UTC(today.getUTCFullYear(), today.getUTCMonth() + 1, 0, 23, 59, 59, 999));

// Find all qualifying free weekday evening classes/workshops this month
const qualifyingEvents = events.filter(e => {
  if (!e || !e.isActive) return false;
  if (e.category !== 'classes_workshops') return false;
  if (!e.isFree && !(typeof e.price === 'number' && e.price === 0)) return false;
  const start = parseIso(e.startDateTime);
  if (!start) return false;
  if (start < monthStart || start > monthEnd) return false;
  const day = start.getUTCDay(); // 0=Sun, 6=Sat
  if (day === 0 || day === 6) return false; // weekdays only
  const mins = minutesOfDay(start);
  if (mins < 17 * 60) return false; // 5:00pm+
  return true;
});

let earliestEvent = null;
if (qualifyingEvents.length > 0) {
  earliestEvent = qualifyingEvents.slice().sort((a, b) => {
    const da = parseIso(a.startDateTime) || 0;
    const db = parseIso(b.startDateTime) || 0;
    return da - db;
  })[0];
}

const qualifyingIds = new Set(qualifyingEvents.map(e => e.id));

// Registration for any qualifying event with correct details
const regForQualifying = regs.find(r => {
  if (!r) return false;
  if (!qualifyingIds.has(r.eventId)) return false;
  if (r.registrantName !== 'Alex Taylor') return false;
  if (r.registrantEmail !== 'alex.taylor@example.com') return false;
  if (r.attendeeCount !== 2) return false;
  return true;
}) || null;

// Registration specifically for the earliest qualifying event
const regForEarliest = regForQualifying && earliestEvent && regForQualifying.eventId === earliestEvent.id;

// CP1 (0.60): User completed a registration for a qualifying event with correct contact info and 2 attendees
checkpoints.push({ passed: !!regForQualifying, weight: 0.6 });

// CP2 (0.40): That registration is for the earliest qualifying event this month
checkpoints.push({ passed: !!regForEarliest, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

function parseIso(d) {
  const dt = new Date(d);
  return isNaN(dt.getTime()) ? null : dt;
}

function minutesOfDay(date) {
  return date.getUTCHours() * 60 + date.getUTCMinutes();
}

function formatDateUTC(d) {
  const y = d.getUTCFullYear();
  const m = String(d.getUTCMonth() + 1).padStart(2, '0');
  const day = String(d.getUTCDate()).padStart(2, '0');
  return y + '-' + m + '-' + day;
}

const rooms = JSON.parse(localStorage.getItem('rooms') || '[]');
const reservations = JSON.parse(localStorage.getItem('room_reservation_requests') || '[]');

// Compute "next Wednesday" relative to current system time
const today = new Date();
const todayDow = today.getUTCDay(); // 0=Sun, 3=Wed
const targetDow = 3; // Wednesday
let daysUntilNextWed = (targetDow - todayDow + 7) % 7;
if (daysUntilNextWed === 0) daysUntilNextWed = 7;
const targetDate = new Date(Date.UTC(today.getUTCFullYear(), today.getUTCMonth(), today.getUTCDate() + daysUntilNextWed));
const targetDateStr = formatDateUTC(targetDate);

// Find reservation that matches date, time window, group size, and contact details
const reservation = reservations.find(r => {
  if (!r) return false;
  const start = parseIso(r.startDateTime);
  const end = parseIso(r.endDateTime);
  if (!start || !end) return false;
  const dateStr = (r.date || '').slice(0, 10);
  if (dateStr !== targetDateStr) return false;
  const startMins = minutesOfDay(start);
  const endMins = minutesOfDay(end);
  if (startMins !== 19 * 60 || endMins !== 21 * 60) return false; // 7–9pm
  if (typeof r.expectedAttendees !== 'number') return false;
  if (r.expectedAttendees < 8 || r.expectedAttendees > 12) return false;
  if (r.groupName !== 'Midweek Bible Study') return false;
  if (r.contactName !== 'John Rivera') return false;
  if (r.contactEmail !== 'john.rivera@example.com') return false;
  return true;
}) || null;

const room = reservation ? rooms.find(ro => ro.id === reservation.roomId) : null;

const roomAccommodates = !!(room && room.isActive && typeof room.capacityMin === 'number' && typeof room.capacityMax === 'number' && reservation.expectedAttendees >= room.capacityMin && reservation.expectedAttendees <= room.capacityMax);

// Determine the available room with lowest capacityMax that can handle ~10 people (8–12)
const targetGroupSize = 10;
const candidateRooms = rooms.filter(ro => {
  if (!ro || !ro.isActive) return false;
  if (typeof ro.capacityMin !== 'number' || typeof ro.capacityMax !== 'number') return false;
  if (targetGroupSize < ro.capacityMin || targetGroupSize > ro.capacityMax) return false;
  return true;
});

let minCapMax = null;
if (candidateRooms.length > 0) {
  minCapMax = candidateRooms.reduce((min, ro) => (min === null || ro.capacityMax < min ? ro.capacityMax : min), null);
}

const choseLowestCapacityRoom = !!(reservation && room && minCapMax !== null && room.capacityMax === minCapMax);

// CP1 (0.60): User submitted a reservation for next Wednesday 7–9pm for 8–12 people with correct contact info and a room that can accommodate the group
checkpoints.push({ passed: !!reservation && roomAccommodates, weight: 0.6 });

// CP2 (0.40): The chosen room has the lowest capacityMax among all rooms that can host a 10-person group
checkpoints.push({ passed: !!reservation && choseLowestCapacityRoom, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

function parseIso(d) {
  const dt = new Date(d);
  return isNaN(dt.getTime()) ? null : dt;
}

const sermons = JSON.parse(localStorage.getItem('sermons') || '[]');
const playlists = JSON.parse(localStorage.getItem('watch_later_playlists') || '[]');
const playlist = playlists[0] || { sermonIds: [] };
const watchIds = Array.isArray(playlist.sermonIds) ? playlist.sermonIds : [];

const today = new Date();
const sixMonthsAgo = new Date(Date.UTC(today.getUTCFullYear(), today.getUTCMonth() - 6, today.getUTCDate()));

// All forgiveness sermons from the last 6 months
const forgivenessRecent = sermons.filter(s => {
  if (!s || !s.isActive) return false;
  if (!Array.isArray(s.topics) || s.topics.indexOf('forgiveness') === -1) return false;
  const d = parseIso(s.date);
  if (!d) return false;
  if (d < sixMonthsAgo || d > today) return false;
  return true;
});

forgivenessRecent.sort((a, b) => {
  const da = parseIso(a.date) || 0;
  const db = parseIso(b.date) || 0;
  return db - da; // newest first
});

const top3 = forgivenessRecent.slice(0, 3);
const top3Ids = top3.map(s => s.id);
const qualifyingCount = top3Ids.filter(id => watchIds.indexOf(id) !== -1).length;

// CP1–3: Number of top-3 forgiveness sermons recently added to Watch Later
const weights = [0.34, 0.33, 0.33];
[1, 2, 3].forEach((n, idx) => {
  checkpoints.push({ passed: qualifyingCount >= n, weight: weights[idx] });
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const roles = JSON.parse(localStorage.getItem('volunteer_roles') || '[]');
const interests = JSON.parse(localStorage.getItem('volunteer_interests') || '[]');

// Qualifying Saturday roles with < 3 hours/week
const qualifyingRoles = roles.filter(r => {
  if (!r || !r.isActive) return false;
  if (!Array.isArray(r.daysNeeded) || r.daysNeeded.indexOf('saturday') === -1) return false;
  if (typeof r.hoursPerWeek !== 'number') return false;
  return r.hoursPerWeek < 3;
});

const qualifyingRoleIds = new Set(qualifyingRoles.map(r => r.id));

// Interest submitted for one of those roles with correct contact details
const interest = interests.find(i => {
  if (!i) return false;
  if (!qualifyingRoleIds.has(i.volunteerRoleId)) return false;
  if (i.name !== 'Maria Lopez') return false;
  if (i.email !== 'maria.lopez@example.com') return false;
  if (i.preferredDay !== 'saturday') return false;
  if (i.preferredTimeWindowStart !== '08:00') return false;
  if (i.preferredTimeWindowEnd !== '10:00') return false;
  return true;
}) || null;

// Single checkpoint: correct role and correct form details
checkpoints.push({ passed: !!interest, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const pledges = JSON.parse(localStorage.getItem('pledges') || '[]');
const funds = JSON.parse(localStorage.getItem('funds') || '[]');
const ministries = JSON.parse(localStorage.getItem('ministries') || '[]');

// Identify youth ministry entities
const youthMinistries = ministries.filter(m => m && typeof m.name === 'string' && m.name.toLowerCase().includes('youth'));
const youthMinistryIds = new Set(youthMinistries.map(m => m.id));

// Funds that correspond to youth ministries and are active & visible online
const youthFundIds = new Set(
  funds
    .filter(f => f && f.isActive && f.isVisibleOnline && youthMinistryIds.has(f.ministryId))
    .map(f => f.id)
);

const maxAmount = 25;

// Look for a pledge meeting all criteria
const pledge = pledges.find(p => {
  if (!p) return false;
  if (!youthFundIds.has(p.fundId)) return false;
  if (p.givingType !== 'pledge_only') return false;
  if (p.frequency !== 'one_time') return false;
  if (p.amount !== maxAmount) return false;
  if (p.donorName !== 'Daniel Kim') return false;
  if (p.donorEmail !== 'daniel.kim@example.com') return false;
  return true;
}) || null;

checkpoints.push({ passed: !!pledge, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

function parseIso(d) {
  const dt = new Date(d);
  return isNaN(dt.getTime()) ? null : dt;
}

function minutesOfDay(date) {
  return date.getUTCHours() * 60 + date.getUTCMinutes();
}

function weekStartMondayUTC(d) {
  const day = d.getUTCDay(); // 0=Sun,1=Mon,...
  const diff = (day + 6) % 7; // 0 for Monday
  const monday = new Date(Date.UTC(d.getUTCFullYear(), d.getUTCMonth(), d.getUTCDate() - diff));
  monday.setUTCHours(0, 0, 0, 0);
  return monday;
}

const events = JSON.parse(localStorage.getItem('events') || '[]');
const lists = JSON.parse(localStorage.getItem('saved_event_lists') || '[]');
const list = lists[0] || { eventIds: [] };
const savedIds = new Set(Array.isArray(list.eventIds) ? list.eventIds : []);

const savedCommunityEvents = events.filter(e => e && e.isActive && e.category === 'community' && savedIds.has(e.id));

const qualifyingFirstEvents = [];
let hasQualifyingPair = false;

for (let i = 0; i < savedCommunityEvents.length; i++) {
  const e1 = savedCommunityEvents[i];
  const s1 = parseIso(e1.startDateTime);
  const e1End = parseIso(e1.endDateTime);
  if (!s1 || !e1End) continue;
  const startMins1 = minutesOfDay(s1);
  // Afternoon start between 12:00 and 17:00 inclusive
  if (startMins1 < 12 * 60 || startMins1 > 17 * 60) continue;
  qualifyingFirstEvents.push(e1);
  const week1 = weekStartMondayUTC(s1).getTime();

  for (let j = 0; j < savedCommunityEvents.length; j++) {
    if (i === j) continue;
    const e2 = savedCommunityEvents[j];
    const s2 = parseIso(e2.startDateTime);
    const e2End = parseIso(e2.endDateTime);
    if (!s2 || !e2End) continue;
    const week2 = weekStartMondayUTC(s2).getTime();
    if (week1 !== week2) continue; // must be same Monday–Sunday week
    const gapMinutes = (s2 - e1End) / 60000;
    if (gapMinutes >= 60) {
      hasQualifyingPair = true;
      break;
    }
  }
  if (hasQualifyingPair) break;
}

const hasFirstAfternoon = qualifyingFirstEvents.length > 0;

// CP1 (0.40): At least one saved community event starts in the afternoon (12–17)
checkpoints.push({ passed: hasFirstAfternoon, weight: 0.4 });

// CP2 (0.60): There exists a pair of saved community events in the same week with the second starting >=1 hour after the first ends (non-overlapping)
checkpoints.push({ passed: hasQualifyingPair, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

function parseIso(d) {
  const dt = new Date(d);
  return isNaN(dt.getTime()) ? null : dt;
}

function minutesOfDay(date) {
  return date.getUTCHours() * 60 + date.getUTCMinutes();
}

const pastors = JSON.parse(localStorage.getItem('pastors') || '[]');
const slots = JSON.parse(localStorage.getItem('counseling_availability_slots') || '[]');
const requests = JSON.parse(localStorage.getItem('counseling_appointment_requests') || '[]');

// Pastors with marriage-related specialties
const marriagePastors = pastors.filter(p => {
  if (!p || !p.isCounselor || !p.isActive) return false;
  const specs = Array.isArray(p.specialties) ? p.specialties : [];
  return specs.some(s => s === 'marriage_counseling' || s === 'marriage_and_family');
});

const marriagePastorIds = new Set(marriagePastors.map(p => p.id));

// The request we expect: by Samantha Green with given email
const candidateRequest = requests.find(r => r && r.name === 'Samantha Green' && r.email === 'samantha.green@example.com') || null;

let pastorIsValid = false;
let slotInNextWeekMorning = false;
let choseEarliestSlot = false;

if (candidateRequest && marriagePastorIds.has(candidateRequest.pastorId) && candidateRequest.reason === 'marriage_counseling') {
  pastorIsValid = true;

  const today = new Date();
  today.setUTCHours(0, 0, 0, 0);
  const day = today.getUTCDay(); // 0=Sun
  // Monday of next week
  let daysToNextMonday = (1 - day + 7) % 7;
  if (daysToNextMonday === 0) daysToNextMonday = 7;
  const weekStart = new Date(today);
  weekStart.setUTCDate(today.getUTCDate() + daysToNextMonday);
  const weekEnd = new Date(weekStart);
  weekEnd.setUTCDate(weekStart.getUTCDate() + 6);
  weekEnd.setUTCHours(23, 59, 59, 999);

  const slot = slots.find(s => s && s.id === candidateRequest.availabilitySlotId && s.pastorId === candidateRequest.pastorId) || null;
  const slotStart = slot ? parseIso(slot.startDateTime) : null;
  const slotEnd = slot ? parseIso(slot.endDateTime) : null;

  if (slot && slotStart && slotEnd && slotStart >= weekStart && slotStart <= weekEnd) {
    const mins = minutesOfDay(slotStart);
    if (mins >= 9 * 60 && mins <= 12 * 60) {
      slotInNextWeekMorning = true;

      // Determine earliest available slot (next week, 9–12) that was still free at the time this request was submitted
      const submittedAt = parseIso(candidateRequest.submittedAt) || new Date(0);

      const availableSlotsAtThatTime = slots.filter(s => {
        if (!s || s.pastorId !== candidateRequest.pastorId) return false;
        const st = parseIso(s.startDateTime);
        if (!st || st < weekStart || st > weekEnd) return false;
        const m = minutesOfDay(st);
        if (m < 9 * 60 || m > 12 * 60) return false;
        // Exclude slots already reserved by earlier requests
        const reservedEarlier = requests.some(r => r && r.availabilitySlotId === s.id && parseIso(r.submittedAt) < submittedAt);
        if (reservedEarlier) return false;
        return true;
      });

      if (availableSlotsAtThatTime.length > 0) {
        availableSlotsAtThatTime.sort((a, b) => {
          const da = parseIso(a.startDateTime) || 0;
          const db = parseIso(b.startDateTime) || 0;
          return da - db;
        });
        const earliestSlot = availableSlotsAtThatTime[0];
        choseEarliestSlot = earliestSlot && slot && earliestSlot.id === slot.id;
      }
    }
  }
}

// CP1 (0.40): Request is with an active counseling pastor who specializes in marriage, with reason 'marriage_counseling'
checkpoints.push({ passed: !!candidateRequest && pastorIsValid, weight: 0.4 });

// CP2 (0.30): Selected slot is next week and between 9:00am and 12:00pm
checkpoints.push({ passed: !!candidateRequest && pastorIsValid && slotInNextWeekMorning, weight: 0.3 });

// CP3 (0.30): Selected slot is the earliest available qualifying slot at the time of request
checkpoints.push({ passed: !!candidateRequest && pastorIsValid && slotInNextWeekMorning && choseEarliestSlot, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
